void main() {
  var tags1 = {'dart', 'flutter', 'mobile'};
  var tags2 = {'flutter', 'web', 'desktop'};

  var allTags = tags1.union(tags2);
  var commonTags = tags1.intersection(tags2);
  var onlyInFirst = tags1.difference(tags2);

  print('All tags: $allTags');
  print('Common: $commonTags');
  print('Only in first: $onlyInFirst');

  // Remove duplicates from list
  var items = ['a', 'b', 'a', 'c', 'b', 'd'];
  var unique = items.toSet().toList();
  print('Unique items: $unique');
}
